CREATE TABLE _hydra_difficulty_rows AS
WITH difficulty_slices AS (
  SELECT
    hpr.source_report_key,
    hpr.starts_on,
    hpr.ends_on,
    hpr.display_name,
    'normal' AS difficulty,
    hpr.normal_damage AS total_damage
  FROM _hydra_player_rows AS hpr
  WHERE hpr.normal_damage > 0

  UNION ALL

  SELECT
    hpr.source_report_key,
    hpr.starts_on,
    hpr.ends_on,
    hpr.display_name,
    'hard' AS difficulty,
    hpr.hard_damage AS total_damage
  FROM _hydra_player_rows AS hpr
  WHERE hpr.hard_damage > 0

  UNION ALL

  SELECT
    hpr.source_report_key,
    hpr.starts_on,
    hpr.ends_on,
    hpr.display_name,
    'brutal' AS difficulty,
    hpr.brutal_damage AS total_damage
  FROM _hydra_player_rows AS hpr
  WHERE hpr.brutal_damage > 0

  UNION ALL

  SELECT
    hpr.source_report_key,
    hpr.starts_on,
    hpr.ends_on,
    hpr.display_name,
    'nightmare' AS difficulty,
    hpr.nightmare_damage AS total_damage
  FROM _hydra_player_rows AS hpr
  WHERE hpr.nightmare_damage > 0
)
SELECT
  ds.source_report_key,
  ds.starts_on,
  ds.ends_on,
  ds.display_name,
  ds.difficulty,
  ds.total_damage,
  ROW_NUMBER() OVER (
    PARTITION BY ds.source_report_key, ds.display_name
    ORDER BY ds.total_damage DESC,
      CASE ds.difficulty
        WHEN 'nightmare' THEN 1
        WHEN 'brutal' THEN 2
        WHEN 'hard' THEN 3
        ELSE 4
      END ASC
  ) AS team_index
FROM difficulty_slices AS ds;

INSERT OR IGNORE INTO competition_window (
  activity_type,
  season_year,
  week_of_year,
  cadence_slot,
  rotation_number,
  starts_at,
  ends_at,
  label
)
SELECT DISTINCT
  'hydra',
  CAST(strftime('%Y', hw.ends_on) AS INTEGER) AS season_year,
  CAST(strftime('%W', hw.ends_on) AS INTEGER) + 1 AS week_of_year,
  'weekly',
  ((CAST(strftime('%W', hw.ends_on) AS INTEGER) % 4) + 1) AS rotation_number,
  hw.starts_on || 'T00:00:00Z',
  hw.ends_on || 'T00:00:00Z',
  'Hydra ' || hw.source_report_key
FROM _hydra_windows AS hw;

INSERT OR IGNORE INTO player_profile (main_nickname, status)
SELECT DISTINCT
  hpr.display_name,
  'active'
FROM _hydra_player_rows AS hpr;

INSERT OR IGNORE INTO player_alias (
  player_profile_id,
  alias_type,
  alias_value,
  is_primary,
  first_seen_at,
  last_seen_at
)
SELECT
  pp.id,
  'game_nickname',
  hpr.display_name,
  1,
  MIN(hpr.starts_on || 'T00:00:00Z'),
  MAX(hpr.ends_on || 'T00:00:00Z')
FROM _hydra_player_rows AS hpr
JOIN player_profile AS pp
  ON pp.main_nickname = hpr.display_name
GROUP BY pp.id, hpr.display_name;

INSERT INTO report_import (
  upload_type,
  source_kind,
  scope_type,
  scope_key,
  replace_existing,
  status,
  started_at,
  finished_at,
  notes
)
SELECT DISTINCT
  'admin_bulk_json',
  'historical_data_hydra',
  'competition_window',
  'hydra:' || hw.source_report_key,
  1,
  'applied',
  CURRENT_TIMESTAMP,
  CURRENT_TIMESTAMP,
  'Imported from historical-data-hydra.json'
FROM _hydra_windows AS hw
WHERE NOT EXISTS (
  SELECT 1
  FROM report_import AS ri
  WHERE ri.upload_type = 'admin_bulk_json'
    AND ri.source_kind = 'historical_data_hydra'
    AND ri.scope_type = 'competition_window'
    AND ri.scope_key = 'hydra:' || hw.source_report_key
);

INSERT OR IGNORE INTO hydra_report (
  competition_window_id,
  report_import_id,
  source_report_key,
  source_system,
  is_partial
)
SELECT
  cw.id,
  (
    SELECT ri.id
    FROM report_import AS ri
    WHERE ri.scope_type = 'competition_window'
      AND ri.scope_key = 'hydra:' || hw.source_report_key
    ORDER BY ri.id DESC
    LIMIT 1
  ) AS report_import_id,
  hw.source_report_key,
  'historical-data-hydra.json',
  1
FROM _hydra_windows AS hw
JOIN competition_window AS cw
  ON cw.activity_type = 'hydra'
  AND cw.cadence_slot = 'weekly'
  AND cw.starts_at = hw.starts_on || 'T00:00:00Z'
  AND cw.ends_at = hw.ends_on || 'T00:00:00Z';

WITH ranked_rows AS (
  SELECT
    hpr.source_report_key,
    hpr.starts_on,
    hpr.ends_on,
    hpr.display_name,
    hpr.total_damage,
    hpr.keys_used,
    ROW_NUMBER() OVER (
      PARTITION BY hpr.source_report_key
      ORDER BY hpr.total_damage DESC, hpr.display_name ASC
    ) AS clan_rank
  FROM _hydra_player_rows AS hpr
)
INSERT INTO hydra_player_result (
  hydra_report_id,
  player_profile_id,
  display_name_at_import,
  total_damage,
  keys_used,
  clan_rank,
  data_completeness
)
SELECT
  hr.id,
  COALESCE(pa.player_profile_id, pp.id),
  rr.display_name,
  rr.total_damage,
  rr.keys_used,
  rr.clan_rank,
  'aggregate_only'
FROM ranked_rows AS rr
JOIN competition_window AS cw
  ON cw.activity_type = 'hydra'
  AND cw.cadence_slot = 'weekly'
  AND cw.starts_at = rr.starts_on || 'T00:00:00Z'
  AND cw.ends_at = rr.ends_on || 'T00:00:00Z'
JOIN hydra_report AS hr
  ON hr.competition_window_id = cw.id
LEFT JOIN player_alias AS pa
  ON pa.alias_type = 'game_nickname'
  AND pa.alias_value = rr.display_name
LEFT JOIN player_profile AS pp
  ON pp.main_nickname = rr.display_name
WHERE COALESCE(pa.player_profile_id, pp.id) IS NOT NULL
ON CONFLICT (hydra_report_id, player_profile_id) DO UPDATE SET
  display_name_at_import = excluded.display_name_at_import,
  total_damage = excluded.total_damage,
  keys_used = excluded.keys_used,
  clan_rank = excluded.clan_rank,
  data_completeness = excluded.data_completeness;

INSERT INTO hydra_team_run (
  hydra_player_result_id,
  hydra_report_id,
  competition_window_id,
  player_profile_id,
  team_index,
  difficulty,
  total_damage,
  attempt_order,
  data_completeness
)
SELECT
  hpr.id,
  hr.id,
  cw.id,
  hpr.player_profile_id,
  hdr.team_index,
  hdr.difficulty,
  hdr.total_damage,
  hdr.team_index,
  'aggregate_only'
FROM _hydra_difficulty_rows AS hdr
JOIN competition_window AS cw
  ON cw.activity_type = 'hydra'
  AND cw.cadence_slot = 'weekly'
  AND cw.starts_at = hdr.starts_on || 'T00:00:00Z'
  AND cw.ends_at = hdr.ends_on || 'T00:00:00Z'
JOIN hydra_report AS hr
  ON hr.competition_window_id = cw.id
LEFT JOIN player_alias AS pa
  ON pa.alias_type = 'game_nickname'
  AND pa.alias_value = hdr.display_name
LEFT JOIN player_profile AS pp
  ON pp.main_nickname = hdr.display_name
JOIN hydra_player_result AS hpr
  ON hpr.hydra_report_id = hr.id
  AND hpr.player_profile_id = COALESCE(pa.player_profile_id, pp.id)
ON CONFLICT (hydra_player_result_id, team_index) DO UPDATE SET
  hydra_report_id = excluded.hydra_report_id,
  competition_window_id = excluded.competition_window_id,
  player_profile_id = excluded.player_profile_id,
  difficulty = excluded.difficulty,
  total_damage = excluded.total_damage,
  attempt_order = excluded.attempt_order,
  data_completeness = excluded.data_completeness;

DROP TABLE IF EXISTS _hydra_difficulty_rows;
DROP TABLE IF EXISTS _hydra_player_rows;
DROP TABLE IF EXISTS _hydra_windows;
